    toc_launch: "Primer lanzamiento versus regreso",
    toc_sound: "Abra el módulo de ayuda y sonido de Windows",
    toc_summary: "Resumen de configuración (Quest/VRChat/Windows)",
    toc_vrchat: "VRChat (solo en el juego)",
    toc_persist: "Opcional: hacer que los dispositivos se peguen",
    toc_config: "Desactivar la prueba automática de cables",
