    toc_title: "Sur cette page",
    toc_flow: "Débit recommandé",
    toc_startup: "Configuration automatique au démarrage",
    toc_launch: "Premier lancement ou retour",
    toc_sound: "Ouvrez le module Windows Sound & Helper",
    toc_summary: "Résumé de la configuration (Quête / VRChat / Windows)",
    toc_vrchat: "VRChat (dans le jeu uniquement)",
