    toc_summary: "Installatieoverzicht (Quest / VRChat / Windows)",
    toc_vrchat: "VRChat (alleen in-game)",
    toc_persist: "Optioneel: laat apparaten plakken",
    toc_config: "Schakel de automatische kabeltest uit",
