    p_startup2: "Het zoekt naar uw microfoon, hoofdtelefoon, virtuele kabel en inkomende (game)audio en doet vervolgens het volgende:",
    li_su1: "Schrijft de resultaten naar <code style=\"background:rgba(0,212,255,0.1);color:var(--cyan);padding:0.12rem 0.4rem;border-radius:4px;font-size:0.9em\">config.ini</code>",
    li_su2: "Vernieuwt de vervolgkeuzelijsten van het tabblad Audio, zodat ze overeenkomen",
    h2_launch: "Eerste lancering versus terugkeer",
