    p_sound2: "De draagbare build bevat een kleine helper, <code style=\"background:rgba(0,212,255,0.1);color:var(--cyan);padding:0.12rem 0.4rem;border-radius:4px;font-size:0.9em\">_windows_audio.py</code>:",
