    th_where: "Waar",
    th_what: "Wat in te stellen",
    tr_q_title: "<strong>Zoektocht (Microfoon)</strong>",
    tr_q_cell: "Microfoon → <code style=\"background:rgba(0,212,255,0.1);color:var(--cyan);padding:0.12rem 0.4rem;border-radius:4px;font-size:0.9em\">CABLE Output (VB-Audio Cable A)</code>",
    tr_vc_title: "<strong>VRChat (in-game)</strong>",
    tr_vc_cell: "<strong>Ingang (microfoon)</strong> → <code style=\"background:rgba(0,212,255,0.1);color:var(--cyan);padding:0.12rem 0.4rem;border-radius:4px;font-size:0.9em\">CABLE Output (VB-Audio Cable A)</code><br><br><strong>Uitvoer</strong> → <code style=\"background:rgba(0,212,255,0.1);color:var(--cyan);padding:0.12rem 0.4rem;border-radius:4px;font-size:0.9em\">CABLE Input (VB-Audio Cable B)</code>voor bidirectioneel,<em>of</em>uw hoofdtelefoon voor alleen-luisteren-opstellingen.",
    tr_win_title: "<strong>Windows-geluid (mixer)</strong>",
    tr_win_cell: "<strong>Ingang (opname)</strong> →uw fysieke microfoon<br><br><strong>Uitvoer (afspelen)</strong> →uw hoofdtelefoon",
    h2_vrc_title: "VRChat kan niet worden ingesteld door de app",
    notice_h: "Handmatige stap",
    notice_p: "S2S verandert de microfoon of luidspreker van VRChat niet voor u. U kiest deze in de instellingen van VRChat. In het installatieoverzicht ziet u welke apparaatnaam u moet kiezen, zodat deze overeenkomt met de kabeltest.",
    h2_persist: "Optioneel: permanente apparaatselectie",
    p_persist: "Om ervoor te zorgen dat de juiste eindpunten behouden blijven bij opnieuw opstarten, voert u de Audio Wizard uit op het tabblad Audio terwijl uw <strong>Quest</strong>-headset is ingeschakeld en aangesloten, en slaat u vervolgens op. Dat werkt <code style=\"background:rgba(0,212,255,0.1);color:var(--cyan);padding:0.12rem 0.4rem;border-radius:4px;font-size:0.9em\">config.ini</code> bij met de juiste apparaat-ID's voor uw installatie.",
    h2_config: "Schakel de automatische kabeltest bij opstarten uit",
    p_config1: "Als u de kabeltest liever alleen handmatig uitvoert, bewerkt u <code style=\"background:rgba(0,212,255,0.1);color:var(--cyan);padding:0.12rem 0.4rem;border-radius:4px;font-size:0.9em\">config.ini</code>:",
    info_config: "<p style=\"margin:0;\"><code style=\"background:rgba(0,212,255,0.1);color:var(--cyan);padding:0.12rem 0.4rem;border-radius:4px;font-size:0.9em\">[AUDIO]</code><br><code style=\"background:rgba(0,212,255,0.1);color:var(--cyan);padding:0.12rem 0.4rem;border-radius:4px;font-size:0.9em\">auto_configure_cables = false</code></p>",
    p_config2: "Standaard is<code style=\"background:rgba(0,212,255,0.1);color:var(--cyan);padding:0.12rem 0.4rem;border-radius:4px;font-size:0.9em\">true</code>zodat nieuwe installaties automatisch hulp krijgen.",
    also_see: "Zie ook<a href=\"S2S_Portable_Download.html#setup\" style=\"color:var(--cyan);\">Downloadpagina — Vereisten voor VB-Audio</a>En<a href=\"S2S_Portable_Manual.html#apps\" style=\"color:var(--cyan);\">Handleiding §7 (VRChat & apps)</a>.",
    footer_home: "Thuis",
