I18N["ZH-TW"] = I18N.ZH; I18N["ZH-HK"] = I18N.ZH; I18N["PT-BR"] = I18N.PT;

function vbacToggleLangDrop(){
  const d=document.getElementById('langDrop');
  const b=document.getElementById('langSwitcherBtn');
  if(!d||!b) return;
  d.classList.toggle('open');
  b.setAttribute('aria-expanded', d.classList.contains('open') ? 'true' : 'false');
}

function vbacBuildDropdown(){
  const d=document.getElementById('langDrop');
  if(!d) return;
  d.innerHTML='';
  LANGS.forEach(l=>{
    d.innerHTML+=`<div class=\"lang-option\" role=\"option\" tabindex=\"0\" onclick=\"vbacSwitchLang('${l.code}')\"><span class=\"mini-flag\" style=\"background:${l.flag}\"></span>${l.name} <span style=\"color:#888;margin-left:auto\">${l.native}</span></div>`;
  });
}

function vbacSwitchLang(code){
  const loc = I18N[code] || I18N[code.substring(0,2)] || I18N.EN;
  const t = Object.assign({}, I18N.EN, loc);
  document.querySelectorAll('[data-i18n]').forEach(el=>{
    const k = el.getAttribute('data-i18n');
    if(t[k]) el.innerHTML = t[k];
  });
  const meta = document.querySelector('meta[name=description]');
  if(meta && t.meta_desc) meta.setAttribute('content', t.meta_desc);
  if(t.doc_title) document.title = t.doc_title;
  document.documentElement.lang = (code==='EN'?'en':code==='JA'?'ja':code==='KO'?'ko':code==='ZH'||code==='ZH-TW'||code==='ZH-HK'?'zh':code==='PT-BR'?'pt-BR':code.toLowerCase().replace('_','-'));
  document.documentElement.dir = (code==='AR') ? 'rtl' : 'ltr';
  const lang = LANGS.find(l=>l.code===code);
  const btn = document.getElementById('langSwitcherBtn');
  const drop = document.getElementById('langDrop');
  if(lang && btn) btn.innerHTML=`<span class=\"mini-flag\" style=\"background:${lang.flag}\"></span>${code} &#9662;`;
  if(drop) drop.classList.remove('open');
  if(btn) btn.setAttribute('aria-expanded','false');
}

document.addEventListener('click',e=>{
  const drop=document.getElementById('langDrop');
  const btn=document.getElementById('langSwitcherBtn');
  if(drop && !e.target.closest('.lang-switcher')) {
    drop.classList.remove('open');
    if(btn) btn.setAttribute('aria-expanded','false');
  }
});
if(document.readyState==='loading') document.addEventListener('DOMContentLoaded',()=>{ vbacBuildDropdown(); });else { vbacBuildDropdown(); }